import{_ as n,c as a,e,o as p}from"./app-DaQSergZ.js";const l={};function t(i,s){return p(),a("div",null,s[0]||(s[0]=[e(`<h1 id="종합-실습" tabindex="-1"><a class="header-anchor" href="#종합-실습"><span>종합 실습</span></a></h1><div class="hint-container info"><p class="hint-container-title">학습 목표</p><ul><li>간단한 웹앱(API 서버 + DB)을 Dockerfile로 빌드하고 레지스트리에 푸시하는 흐름을 익힌다.</li><li>Deployment·Service·Ingress·ConfigMap·Secret·PVC 매니페스트를 하나의 애플리케이션으로 엮어 작성한다.</li><li>probe·HPA·RBAC를 실제 워크로드에 적용해 자가 치유·자동 확장·최소 권한을 구성한다.</li><li>롤링 업데이트와 롤백을 수행하고, 흔한 장애를 <code>kubectl</code>로 진단하는 트러블슈팅 절차를 몸에 익힌다.</li></ul></div><p>지금까지 챕터별로 다룬 오브젝트를 하나의 시나리오로 모은다. 시나리오는 <strong>todo API 서버 + PostgreSQL DB</strong>로 구성된 작은 웹 서비스다. API 서버는 직접 만든 컨테이너 이미지로, DB는 공식 <code>postgres</code> 이미지로 띄운다. 전체 흐름은 다음과 같다.</p><pre class="mermaid">flowchart TD
    A[소스 코드 + Dockerfile] --&gt;|docker build| B[로컬 이미지]
    B --&gt;|docker push| C[컨테이너 레지스트리]
    C --&gt;|image pull| D[Deployment의 Pod]
    E[ConfigMap / Secret] --&gt; D
    F[PVC -&gt; PV] --&gt; G[PostgreSQL StatefulSet]
    D --&gt; H[Service: api-svc]
    G --&gt; I[Service: db-svc]
    H --&gt; J[Ingress]
    J --&gt;|외부 트래픽| K[사용자]
    L[HPA] --&gt;|replicas 조절| D
    M[ServiceAccount + Role] --&gt;|RBAC| D
</pre><h2 id="_1-애플리케이션과-dockerfile" tabindex="-1"><a class="header-anchor" href="#_1-애플리케이션과-dockerfile"><span>1. 애플리케이션과 Dockerfile</span></a></h2><p>API 서버는 <code>/healthz</code>(liveness), <code>/readyz</code>(readiness), <code>/todos</code>(기능) 세 엔드포인트를 가진다고 가정한다. 환경변수로 DB 접속 정보를 받는다. 핵심은 매니페스트이므로 애플리케이션 코드 자체는 최소화하고 Dockerfile에 집중한다.</p><div class="language-docker line-numbers-mode" data-highlighter="prismjs" data-ext="docker" data-title="docker"><pre><code><span class="line"><span class="token comment"># syntax=docker/dockerfile:1</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">FROM</span> node:20-alpine <span class="token keyword">AS</span> build</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">WORKDIR</span> /app</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">COPY</span> package*.json ./</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">RUN</span> npm ci --omit=dev</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">COPY</span> . .</span></span>
<span class="line"></span>
<span class="line"><span class="token instruction"><span class="token keyword">FROM</span> node:20-alpine</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">WORKDIR</span> /app</span></span>
<span class="line"><span class="token comment"># 비루트 사용자로 실행 — 보안 기본값</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">RUN</span> addgroup -S app &amp;&amp; adduser -S app -G app</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">COPY</span> <span class="token options"><span class="token property">--from</span><span class="token punctuation">=</span><span class="token string">build</span></span> /app /app</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">USER</span> app</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">EXPOSE</span> 8080</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">ENV</span> NODE_ENV=production</span></span>
<span class="line"><span class="token instruction"><span class="token keyword">CMD</span> [<span class="token string">&quot;node&quot;</span>, <span class="token string">&quot;server.js&quot;</span>]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>멀티스테이지 빌드로 빌드 의존성을 최종 이미지에서 제외하고, <code>USER app</code>으로 비루트 실행을 강제했다. 이미지 빌드 모범 사례는 <a href="https://docs.docker.com/build/building/best-practices/" target="_blank" rel="noopener noreferrer">이미지 빌드 베스트 프랙티스</a> 문서를 참고한다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line"><span class="token comment"># 이미지 빌드 — 레지스트리 경로를 태그로 직접 지정</span></span>
<span class="line"><span class="token function">docker</span> build <span class="token parameter variable">-t</span> registry.example.com/todo-api:1.0.0 <span class="token builtin class-name">.</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 레지스트리 로그인 후 푸시</span></span>
<span class="line"><span class="token function">docker</span> login registry.example.com</span>
<span class="line"><span class="token function">docker</span> push registry.example.com/todo-api:1.0.0</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>태그에는 <code>latest</code> 대신 <code>1.0.0</code> 같은 명시적 버전을 쓴다. <code>latest</code>는 어떤 빌드가 떠 있는지 추적이 어렵고, <code>imagePullPolicy</code> 기본 동작과 맞물려 예측 불가능한 배포를 유발한다.</p><h2 id="_2-네임스페이스와-설정-—-configmap-secret" tabindex="-1"><a class="header-anchor" href="#_2-네임스페이스와-설정-—-configmap-secret"><span>2. 네임스페이스와 설정 — ConfigMap, Secret</span></a></h2><p>먼저 애플리케이션을 격리할 네임스페이스를 만든다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl create namespace todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>비밀이 아닌 설정은 ConfigMap, 비밀번호 같은 민감 정보는 Secret으로 분리한다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> ConfigMap</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>config</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">data</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">LOG_LEVEL</span><span class="token punctuation">:</span> <span class="token string">&quot;info&quot;</span></span>
<span class="line">  <span class="token key atrule">DB_HOST</span><span class="token punctuation">:</span> <span class="token string">&quot;db-svc&quot;</span></span>
<span class="line">  <span class="token key atrule">DB_PORT</span><span class="token punctuation">:</span> <span class="token string">&quot;5432&quot;</span></span>
<span class="line">  <span class="token key atrule">DB_NAME</span><span class="token punctuation">:</span> <span class="token string">&quot;todo&quot;</span></span>
<span class="line"><span class="token punctuation">---</span></span>
<span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Secret</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>secret</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">type</span><span class="token punctuation">:</span> Opaque</span>
<span class="line"><span class="token key atrule">stringData</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">DB_USER</span><span class="token punctuation">:</span> <span class="token string">&quot;todo&quot;</span></span>
<span class="line">  <span class="token key atrule">DB_PASSWORD</span><span class="token punctuation">:</span> <span class="token string">&quot;s3cr3t-change-me&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>stringData</code>를 쓰면 평문으로 적어도 API 서버가 저장 시 base64로 인코딩한다. 다만 base64는 암호화가 아니므로, 실제 운영에서는 <a href="https://kubernetes.io/docs/concepts/configuration/secret/#information-security-for-secrets" target="_blank" rel="noopener noreferrer">Secret 보안</a>에 따라 etcd 암호화나 외부 시크릿 매니저를 함께 쓴다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> config.yaml</span>
<span class="line">kubectl get configmap,secret <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-db-계층-—-pvc-statefulset-service" tabindex="-1"><a class="header-anchor" href="#_3-db-계층-—-pvc-statefulset-service"><span>3. DB 계층 — PVC, StatefulSet, Service</span></a></h2><p>DB는 데이터를 잃으면 안 되므로 영속 볼륨이 필요하다. StatefulSet의 <code>volumeClaimTemplates</code>로 Pod마다 안정적인 PVC를 받게 한다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Service</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> db<span class="token punctuation">-</span>svc</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">clusterIP</span><span class="token punctuation">:</span> None        <span class="token comment"># 헤드리스 — StatefulSet 안정 네트워크 식별자용</span></span>
<span class="line">  <span class="token key atrule">selector</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">app</span><span class="token punctuation">:</span> db</span>
<span class="line">  <span class="token key atrule">ports</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">5432</span></span>
<span class="line">    <span class="token key atrule">targetPort</span><span class="token punctuation">:</span> <span class="token number">5432</span></span>
<span class="line"><span class="token punctuation">---</span></span>
<span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> StatefulSet</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> db</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">serviceName</span><span class="token punctuation">:</span> db<span class="token punctuation">-</span>svc</span>
<span class="line">  <span class="token key atrule">replicas</span><span class="token punctuation">:</span> <span class="token number">1</span></span>
<span class="line">  <span class="token key atrule">selector</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">matchLabels</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">app</span><span class="token punctuation">:</span> db</span>
<span class="line">  <span class="token key atrule">template</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">labels</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token key atrule">app</span><span class="token punctuation">:</span> db</span>
<span class="line">    <span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">containers</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> postgres</span>
<span class="line">        <span class="token key atrule">image</span><span class="token punctuation">:</span> postgres<span class="token punctuation">:</span>16<span class="token punctuation">-</span>alpine</span>
<span class="line">        <span class="token key atrule">ports</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">containerPort</span><span class="token punctuation">:</span> <span class="token number">5432</span></span>
<span class="line">        <span class="token key atrule">env</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> POSTGRES_DB</span>
<span class="line">          <span class="token key atrule">valueFrom</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">configMapKeyRef</span><span class="token punctuation">:</span></span>
<span class="line">              <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>config</span>
<span class="line">              <span class="token key atrule">key</span><span class="token punctuation">:</span> DB_NAME</span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> POSTGRES_USER</span>
<span class="line">          <span class="token key atrule">valueFrom</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">secretKeyRef</span><span class="token punctuation">:</span></span>
<span class="line">              <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>secret</span>
<span class="line">              <span class="token key atrule">key</span><span class="token punctuation">:</span> DB_USER</span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> POSTGRES_PASSWORD</span>
<span class="line">          <span class="token key atrule">valueFrom</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">secretKeyRef</span><span class="token punctuation">:</span></span>
<span class="line">              <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>secret</span>
<span class="line">              <span class="token key atrule">key</span><span class="token punctuation">:</span> DB_PASSWORD</span>
<span class="line">        <span class="token key atrule">volumeMounts</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> data</span>
<span class="line">          <span class="token key atrule">mountPath</span><span class="token punctuation">:</span> /var/lib/postgresql/data</span>
<span class="line">        <span class="token key atrule">readinessProbe</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">exec</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">command</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;pg_isready&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-U&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;todo&quot;</span><span class="token punctuation">]</span></span>
<span class="line">          <span class="token key atrule">initialDelaySeconds</span><span class="token punctuation">:</span> <span class="token number">5</span></span>
<span class="line">          <span class="token key atrule">periodSeconds</span><span class="token punctuation">:</span> <span class="token number">10</span></span>
<span class="line">  <span class="token key atrule">volumeClaimTemplates</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">name</span><span class="token punctuation">:</span> data</span>
<span class="line">    <span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">accessModes</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;ReadWriteOnce&quot;</span><span class="token punctuation">]</span></span>
<span class="line">      <span class="token key atrule">resources</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token key atrule">requests</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">storage</span><span class="token punctuation">:</span> 5Gi</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>volumeClaimTemplates</code>는 StatefulSet이 각 Pod(<code>db-0</code>)마다 <code>data-db-0</code> PVC를 자동 생성하게 한다. 자세한 동작은 <a href="https://kubernetes.io/docs/concepts/workloads/controllers/statefulset/" target="_blank" rel="noopener noreferrer">StatefulSet 문서</a>를 참고한다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> db.yaml</span>
<span class="line">kubectl get statefulset,pvc,pod <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-api-계층-—-deployment-probe-리소스" tabindex="-1"><a class="header-anchor" href="#_4-api-계층-—-deployment-probe-리소스"><span>4. API 계층 — Deployment, probe, 리소스</span></a></h2><p>API 서버는 stateless이므로 Deployment로 배포한다. 여기서 liveness/readiness/startup probe와 리소스 요청·제한을 함께 건다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Deployment</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line">  <span class="token key atrule">labels</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">app</span><span class="token punctuation">:</span> api</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">replicas</span><span class="token punctuation">:</span> <span class="token number">2</span></span>
<span class="line">  <span class="token key atrule">selector</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">matchLabels</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">app</span><span class="token punctuation">:</span> api</span>
<span class="line">  <span class="token key atrule">template</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">labels</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token key atrule">app</span><span class="token punctuation">:</span> api</span>
<span class="line">    <span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">serviceAccountName</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>sa     <span class="token comment"># RBAC용 — 5절에서 생성</span></span>
<span class="line">      <span class="token key atrule">containers</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> api</span>
<span class="line">        <span class="token key atrule">image</span><span class="token punctuation">:</span> registry.example.com/todo<span class="token punctuation">-</span>api<span class="token punctuation">:</span>1.0.0</span>
<span class="line">        <span class="token key atrule">ports</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">containerPort</span><span class="token punctuation">:</span> <span class="token number">8080</span></span>
<span class="line">        <span class="token key atrule">envFrom</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">configMapRef</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>config</span>
<span class="line">        <span class="token punctuation">-</span> <span class="token key atrule">secretRef</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>secret</span>
<span class="line">        <span class="token key atrule">resources</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">requests</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">cpu</span><span class="token punctuation">:</span> <span class="token string">&quot;100m&quot;</span></span>
<span class="line">            <span class="token key atrule">memory</span><span class="token punctuation">:</span> <span class="token string">&quot;128Mi&quot;</span></span>
<span class="line">          <span class="token key atrule">limits</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">cpu</span><span class="token punctuation">:</span> <span class="token string">&quot;500m&quot;</span></span>
<span class="line">            <span class="token key atrule">memory</span><span class="token punctuation">:</span> <span class="token string">&quot;256Mi&quot;</span></span>
<span class="line">        <span class="token key atrule">startupProbe</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">httpGet</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">path</span><span class="token punctuation">:</span> /healthz</span>
<span class="line">            <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">8080</span></span>
<span class="line">          <span class="token key atrule">failureThreshold</span><span class="token punctuation">:</span> <span class="token number">30</span></span>
<span class="line">          <span class="token key atrule">periodSeconds</span><span class="token punctuation">:</span> <span class="token number">2</span></span>
<span class="line">        <span class="token key atrule">livenessProbe</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">httpGet</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">path</span><span class="token punctuation">:</span> /healthz</span>
<span class="line">            <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">8080</span></span>
<span class="line">          <span class="token key atrule">periodSeconds</span><span class="token punctuation">:</span> <span class="token number">10</span></span>
<span class="line">        <span class="token key atrule">readinessProbe</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">httpGet</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">path</span><span class="token punctuation">:</span> /readyz</span>
<span class="line">            <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">8080</span></span>
<span class="line">          <span class="token key atrule">periodSeconds</span><span class="token punctuation">:</span> <span class="token number">5</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>startupProbe</code>는 느린 초기화 동안 liveness가 컨테이너를 죽이는 것을 막는다. <code>requests</code>는 스케줄링·HPA 기준이 되고, <code>limits</code>는 노드 자원을 보호한다. probe 종류와 설정은 <a href="https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/" target="_blank" rel="noopener noreferrer">liveness/readiness/startup probe 문서</a>에 자세하다.</p><p>API를 묶는 Service는 ClusterIP로 둔다. 외부 노출은 Ingress가 맡는다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Service</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>svc</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">selector</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">app</span><span class="token punctuation">:</span> api</span>
<span class="line">  <span class="token key atrule">ports</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">80</span></span>
<span class="line">    <span class="token key atrule">targetPort</span><span class="token punctuation">:</span> <span class="token number">8080</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> api.yaml</span>
<span class="line">kubectl apply <span class="token parameter variable">-f</span> api-svc.yaml</span>
<span class="line">kubectl rollout status deployment/api <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_5-rbac-—-serviceaccount-role-rolebinding" tabindex="-1"><a class="header-anchor" href="#_5-rbac-—-serviceaccount-role-rolebinding"><span>5. RBAC — ServiceAccount, Role, RoleBinding</span></a></h2><p>API 서버가 자기 네임스페이스의 ConfigMap을 런타임에 읽어야 한다고 가정하면, 그 권한만 최소로 부여한다. 기본 ServiceAccount에 권한을 몰아주지 말고 전용 SA를 만든다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> ServiceAccount</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>sa</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token punctuation">---</span></span>
<span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> rbac.authorization.k8s.io/v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Role</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> config<span class="token punctuation">-</span>reader</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">rules</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token punctuation">-</span> <span class="token key atrule">apiGroups</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token key atrule">resources</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;configmaps&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token key atrule">verbs</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;get&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;list&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;watch&quot;</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">---</span></span>
<span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> rbac.authorization.k8s.io/v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> RoleBinding</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>config<span class="token punctuation">-</span>reader</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">subjects</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token punctuation">-</span> <span class="token key atrule">kind</span><span class="token punctuation">:</span> ServiceAccount</span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>sa</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">roleRef</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">kind</span><span class="token punctuation">:</span> Role</span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> config<span class="token punctuation">-</span>reader</span>
<span class="line">  <span class="token key atrule">apiGroup</span><span class="token punctuation">:</span> rbac.authorization.k8s.io</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>verbs</code>는 필요한 것만 나열했다. 권한이 제대로 걸렸는지는 <code>auth can-i</code>로 SA를 가장해 확인한다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> rbac.yaml</span>
<span class="line">kubectl auth can-i get configmaps <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--as</span><span class="token operator">=</span>system:serviceaccount:todo:api-sa <span class="token parameter variable">-n</span> todo   <span class="token comment"># yes</span></span>
<span class="line">kubectl auth can-i delete configmaps <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--as</span><span class="token operator">=</span>system:serviceaccount:todo:api-sa <span class="token parameter variable">-n</span> todo   <span class="token comment"># no</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>RBAC 모델 전반은 <a href="https://kubernetes.io/docs/reference/access-authn-authz/rbac/" target="_blank" rel="noopener noreferrer">RBAC 권한 부여 문서</a>에 정리돼 있다.</p><h2 id="_6-ingress-—-외부-노출" tabindex="-1"><a class="header-anchor" href="#_6-ingress-—-외부-노출"><span>6. Ingress — 외부 노출</span></a></h2><p>외부 트래픽을 호스트/경로 기준으로 Service에 라우팅한다. Ingress 컨트롤러(예: ingress-nginx)가 클러스터에 설치돼 있다고 가정한다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> networking.k8s.io/v1</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> Ingress</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> todo<span class="token punctuation">-</span>ingress</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line">  <span class="token key atrule">annotations</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">nginx.ingress.kubernetes.io/rewrite-target</span><span class="token punctuation">:</span> /</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">ingressClassName</span><span class="token punctuation">:</span> nginx</span>
<span class="line">  <span class="token key atrule">rules</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">host</span><span class="token punctuation">:</span> todo.example.com</span>
<span class="line">    <span class="token key atrule">http</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">paths</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> <span class="token key atrule">path</span><span class="token punctuation">:</span> /api</span>
<span class="line">        <span class="token key atrule">pathType</span><span class="token punctuation">:</span> Prefix</span>
<span class="line">        <span class="token key atrule">backend</span><span class="token punctuation">:</span></span>
<span class="line">          <span class="token key atrule">service</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>svc</span>
<span class="line">            <span class="token key atrule">port</span><span class="token punctuation">:</span></span>
<span class="line">              <span class="token key atrule">number</span><span class="token punctuation">:</span> <span class="token number">80</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> ingress.yaml</span>
<span class="line">kubectl get ingress <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>이제 외부 사용자의 요청이 처리되는 경로는 다음과 같다.</p><pre class="mermaid">sequenceDiagram
    participant U as 사용자
    participant ING as Ingress Controller
    participant ASVC as api-svc (ClusterIP)
    participant API as api Pod
    participant DSVC as db-svc
    participant DB as PostgreSQL

    U-&gt;&gt;ING: GET https://todo.example.com/api/todos
    ING-&gt;&gt;ASVC: /todos 로 라우팅
    ASVC-&gt;&gt;API: 엔드포인트(Pod IP)로 로드밸런싱
    API-&gt;&gt;DSVC: SELECT * FROM todos
    DSVC-&gt;&gt;DB: 연결 프록시
    DB--&gt;&gt;API: 결과 행
    API--&gt;&gt;U: 200 OK (JSON)
</pre><p>전체 개념은 <a href="https://kubernetes.io/docs/concepts/services-networking/ingress/" target="_blank" rel="noopener noreferrer">Ingress 문서</a>를 참고한다.</p><h2 id="_7-hpa-—-자동-확장" tabindex="-1"><a class="header-anchor" href="#_7-hpa-—-자동-확장"><span>7. HPA — 자동 확장</span></a></h2><p>부하에 따라 API Pod 수를 늘리고 줄인다. HPA는 4절에서 건 <code>requests.cpu</code>를 기준으로 사용률을 계산하므로, requests가 반드시 설정돼 있어야 한다. metrics-server가 클러스터에 있어야 한다.</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> autoscaling/v2</span>
<span class="line"><span class="token key atrule">kind</span><span class="token punctuation">:</span> HorizontalPodAutoscaler</span>
<span class="line"><span class="token key atrule">metadata</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">name</span><span class="token punctuation">:</span> api<span class="token punctuation">-</span>hpa</span>
<span class="line">  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> todo</span>
<span class="line"><span class="token key atrule">spec</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">scaleTargetRef</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1</span>
<span class="line">    <span class="token key atrule">kind</span><span class="token punctuation">:</span> Deployment</span>
<span class="line">    <span class="token key atrule">name</span><span class="token punctuation">:</span> api</span>
<span class="line">  <span class="token key atrule">minReplicas</span><span class="token punctuation">:</span> <span class="token number">2</span></span>
<span class="line">  <span class="token key atrule">maxReplicas</span><span class="token punctuation">:</span> <span class="token number">10</span></span>
<span class="line">  <span class="token key atrule">metrics</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">type</span><span class="token punctuation">:</span> Resource</span>
<span class="line">    <span class="token key atrule">resource</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token key atrule">name</span><span class="token punctuation">:</span> cpu</span>
<span class="line">      <span class="token key atrule">target</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token key atrule">type</span><span class="token punctuation">:</span> Utilization</span>
<span class="line">        <span class="token key atrule">averageUtilization</span><span class="token punctuation">:</span> <span class="token number">60</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl apply <span class="token parameter variable">-f</span> hpa.yaml</span>
<span class="line">kubectl get hpa <span class="token parameter variable">-n</span> todo <span class="token parameter variable">-w</span>        <span class="token comment"># TARGETS, REPLICAS 변화 관찰</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>평균 CPU 사용률이 60%를 넘으면 replicas를 늘린다. 동작 원리는 <a href="https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale/" target="_blank" rel="noopener noreferrer">HPA 문서</a>에 있다.</p><h2 id="_8-롤링-업데이트와-롤백" tabindex="-1"><a class="header-anchor" href="#_8-롤링-업데이트와-롤백"><span>8. 롤링 업데이트와 롤백</span></a></h2><p>API 코드를 고쳐 <code>1.1.0</code> 이미지를 새로 푸시했다고 하자. Deployment의 이미지 태그만 바꾸면 롤링 업데이트가 시작된다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line"><span class="token comment"># 이미지 교체 — 롤링 업데이트 트리거</span></span>
<span class="line">kubectl <span class="token builtin class-name">set</span> image deployment/api <span class="token assign-left variable">api</span><span class="token operator">=</span>registry.example.com/todo-api:1.1.0 <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 진행 상황 추적</span></span>
<span class="line">kubectl rollout status deployment/api <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 리비전 이력 확인</span></span>
<span class="line">kubectl rollout <span class="token function">history</span> deployment/api <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>새 버전이 잘못됐다면 직전 리비전으로 즉시 롤백한다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">kubectl rollout undo deployment/api <span class="token parameter variable">-n</span> todo</span>
<span class="line"><span class="token comment"># 특정 리비전으로: kubectl rollout undo deployment/api --to-revision=2 -n todo</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>readiness probe가 있으므로, 새 Pod가 <code>/readyz</code>에 200을 줄 때까지 Service 엔드포인트에 추가되지 않는다. 덕분에 업데이트 중에도 트래픽이 준비 안 된 Pod로 가지 않는다.</p><h2 id="_9-트러블슈팅" tabindex="-1"><a class="header-anchor" href="#_9-트러블슈팅"><span>9. 트러블슈팅</span></a></h2><p>배포 후 문제가 생겼을 때의 진단 순서다. 위에서 아래로 좁혀 간다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line"><span class="token comment"># 1) 전체 리소스 상태 한눈에</span></span>
<span class="line">kubectl get all <span class="token parameter variable">-n</span> todo</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 2) Pod가 Pending/CrashLoopBackOff면 이벤트부터</span></span>
<span class="line">kubectl describe pod <span class="token operator">&lt;</span>pod<span class="token operator">&gt;</span> <span class="token parameter variable">-n</span> todo        <span class="token comment"># Events 섹션 확인</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 3) 애플리케이션 로그</span></span>
<span class="line">kubectl logs <span class="token operator">&lt;</span>pod<span class="token operator">&gt;</span> <span class="token parameter variable">-n</span> todo</span>
<span class="line">kubectl logs <span class="token operator">&lt;</span>pod<span class="token operator">&gt;</span> <span class="token parameter variable">-n</span> todo <span class="token parameter variable">--previous</span>      <span class="token comment"># 크래시 직전 로그</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 4) 컨테이너 안에서 직접 확인</span></span>
<span class="line">kubectl <span class="token builtin class-name">exec</span> <span class="token parameter variable">-it</span> <span class="token operator">&lt;</span>pod<span class="token operator">&gt;</span> <span class="token parameter variable">-n</span> todo -- <span class="token function">sh</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>흔한 증상과 원인을 정리한다.</p><table><thead><tr><th>증상</th><th>자주 보는 원인</th><th>확인 명령</th></tr></thead><tbody><tr><td><code>ImagePullBackOff</code></td><td>잘못된 이미지 태그, 레지스트리 인증 누락</td><td><code>kubectl describe pod</code> Events</td></tr><tr><td><code>CrashLoopBackOff</code></td><td>앱 기동 실패, 잘못된 env, DB 연결 불가</td><td><code>kubectl logs --previous</code></td></tr><tr><td>Pod <code>Pending</code></td><td>노드 자원 부족, PVC 바인딩 실패, 셀렉터 불일치</td><td><code>kubectl describe pod</code>, <code>kubectl get pvc</code></td></tr><tr><td>readiness 계속 실패</td><td><code>/readyz</code> 경로·포트 오류, DB 미준비</td><td><code>kubectl describe pod</code>, probe 설정</td></tr><tr><td>Ingress 404/502</td><td><code>ingressClassName</code> 누락, Service 셀렉터 불일치</td><td><code>kubectl get endpoints api-svc -n todo</code></td></tr><tr><td>HPA <code>&lt;unknown&gt;</code> 타겟</td><td>metrics-server 부재, requests 미설정</td><td><code>kubectl top pod -n todo</code></td></tr></tbody></table><p>Service가 Pod를 못 찾는지(엔드포인트 비어 있음)는 특히 자주 막히는 지점이다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line"><span class="token comment"># 엔드포인트가 비어 있으면 Service 셀렉터와 Pod 라벨 불일치를 의심한다</span></span>
<span class="line">kubectl get endpoints api-svc <span class="token parameter variable">-n</span> todo</span>
<span class="line">kubectl get pods <span class="token parameter variable">-n</span> todo --show-labels</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>체계적인 디버깅 흐름은 <a href="https://kubernetes.io/docs/tasks/debug/debug-application/" target="_blank" rel="noopener noreferrer">애플리케이션 트러블슈팅 문서</a>를 참고한다.</p><div class="hint-container tip"><p class="hint-container-title">핵심 정리</p><ul><li>하나의 애플리케이션은 이미지 빌드·푸시 → ConfigMap/Secret → DB(PVC/StatefulSet) → API(Deployment/probe/resources) → RBAC → Service → Ingress → HPA 순으로 쌓아 올린다.</li><li>probe와 리소스 requests는 자가 치유·HPA·무중단 배포의 전제 조건이다. 빠뜨리면 롤링 업데이트와 자동 확장이 의도대로 동작하지 않는다.</li><li>RBAC는 전용 ServiceAccount에 최소 권한만 부여하고 <code>kubectl auth can-i</code>로 검증한다.</li><li>트러블슈팅은 <code>get → describe(Events) → logs(--previous) → exec → endpoints</code> 순으로 좁혀 가는 것이 정석이다.</li></ul></div><h2 id="다음-챕터" tabindex="-1"><a class="header-anchor" href="#다음-챕터"><span>다음 챕터</span></a></h2><p>이것으로 컨테이너부터 클러스터 운영, 멀티테넌시, 종합 실습까지 한 바퀴를 돌았다. 이후 부록에서는 실무에서 곧바로 꺼내 쓰는 <a href="/study/kubernetes/appendix-kubectl-cheatsheet">kubectl 치트시트</a>로 자주 쓰는 명령을 카테고리별로 정리한다.</p>`,64)]))}const o=n(l,[["render",t],["__file","47-practice.html.vue"]]),u=JSON.parse('{"path":"/study/kubernetes/47-practice.html","title":"종합 실습","lang":"en-US","frontmatter":{"title":"종합 실습","description":"API 서버 + DB로 구성된 웹앱을 Dockerfile 빌드부터 이미지 푸시, 매니페스트(Deployment/Service/Ingress/ConfigMap/Secret/PVC) 작성, 배포, HPA·probe·RBAC 적용, 롤링 업데이트, 트러블슈팅까지 하나의 시나리오로 엮어 처음부터 끝까지 따라간다.","date":"2026-06-15T00:00:00.000Z","tags":["Kubernetes","Practice","Deployment","Ingress","HPA","RBAC","Troubleshooting"],"prev":"/study/kubernetes/46-multi-tenancy-cluster","next":"/study/kubernetes/appendix-imperative-drills"},"headers":[{"level":1,"title":"종합 실습","slug":"종합-실습","link":"#종합-실습","children":[{"level":2,"title":"1. 애플리케이션과 Dockerfile","slug":"_1-애플리케이션과-dockerfile","link":"#_1-애플리케이션과-dockerfile","children":[]},{"level":2,"title":"2. 네임스페이스와 설정 — ConfigMap, Secret","slug":"_2-네임스페이스와-설정-—-configmap-secret","link":"#_2-네임스페이스와-설정-—-configmap-secret","children":[]},{"level":2,"title":"3. DB 계층 — PVC, StatefulSet, Service","slug":"_3-db-계층-—-pvc-statefulset-service","link":"#_3-db-계층-—-pvc-statefulset-service","children":[]},{"level":2,"title":"4. API 계층 — Deployment, probe, 리소스","slug":"_4-api-계층-—-deployment-probe-리소스","link":"#_4-api-계층-—-deployment-probe-리소스","children":[]},{"level":2,"title":"5. RBAC — ServiceAccount, Role, RoleBinding","slug":"_5-rbac-—-serviceaccount-role-rolebinding","link":"#_5-rbac-—-serviceaccount-role-rolebinding","children":[]},{"level":2,"title":"6. Ingress — 외부 노출","slug":"_6-ingress-—-외부-노출","link":"#_6-ingress-—-외부-노출","children":[]},{"level":2,"title":"7. HPA — 자동 확장","slug":"_7-hpa-—-자동-확장","link":"#_7-hpa-—-자동-확장","children":[]},{"level":2,"title":"8. 롤링 업데이트와 롤백","slug":"_8-롤링-업데이트와-롤백","link":"#_8-롤링-업데이트와-롤백","children":[]},{"level":2,"title":"9. 트러블슈팅","slug":"_9-트러블슈팅","link":"#_9-트러블슈팅","children":[]},{"level":2,"title":"다음 챕터","slug":"다음-챕터","link":"#다음-챕터","children":[]}]}],"git":{},"filePathRelative":"_study/kubernetes/47-practice.md"}');export{o as comp,u as data};
